module RefModule (
    input [7:0] a,
    input [7:0] b,
    input [7:0] c,
    input [7:0] d,
    input [7:0] e,
    output reg [7:0] median
);

reg [7:0] obf_sorted [0:4];

integer i, j;

always @(*) begin
    // Load inputs into obf_sorted array
    obf_sorted[0] = a;
    obf_sorted[1] = b;
    obf_sorted[2] = c;
    obf_sorted[3] = d;
    obf_sorted[4] = e;

    // Simple bubble sort to sort the array
    for (i = 0; i < 4; i = i + 1) begin
        for (j = 0; j < 4 - i; j = j + 1) begin
            if (obf_sorted[j] > obf_sorted[j + 1]) begin
                // Swap
                {obf_sorted[j], obf_sorted[j + 1]} = {obf_sorted[j + 1], obf_sorted[j]};
            end
        end
    end

    // Select the median (the middle element in the obf_sorted array)
    median = obf_sorted[2];
end

endmodule
